<head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <base href="/" />
    <HeadOutlet @rendermode="PageRenderMode" />
</head>

<body>
    <Routes @rendermode="PageRenderMode" />

    <script src="_framework/blazor.web.js"></script>
</body>

</html>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private IComponentRenderMode? PageRenderMode =>
        AssignedRenderMode(HttpContext);

    /// <summary>
    /// Returns null (static SSR) when the routed page carries [RenderModeAttribute],
    /// otherwise returns InteractiveServer for normal global interactivity.
    /// </summary>
    private static IComponentRenderMode? AssignedRenderMode(HttpContext? httpContext)
    {
        if (httpContext is null)
            return RenderMode.InteractiveServer;

        var endpoint = httpContext.GetEndpoint();
        var hasStaticAttribute = endpoint?.Metadata
            .GetMetadata<BlazorApp.Components.Pages.RenderModeAttribute>();

        if (hasStaticAttribute is not null)
        {
            // Page explicitly opts out of interactive rendering.
            return null;
        }

        return RenderMode.InteractiveServer;
    }
}
"}

